import{a as c}from"./api-B6z0ZZoc.js";import{_ as v}from"./_plugin-vue_export-helper-DlAUqK2U.js";import{o as p,c as s,b as t,A as l,t as o,m as r,F as f,r as m,f as b,i as g,l as i,B as h}from"./index-jnpU4DE0.js";const q={class:"liste",style:{"max-width":"780px"}},x={key:0,class:"item"},_={class:"detail"},C={key:0},k={key:1},w={class:"fraicheur"},L={class:"quand"},j={__name:"AProposView",setup(y){const a=g(null);function u(d){const e=(Date.now()-new Date(d).getTime())/36e5;return e<1.5?"collectée à l'instant":e<36?`collectée il y a ${Math.round(e)} h`:`collectée il y a ${Math.round(e/24)} j`}return p(async()=>{try{a.value=await c("/sources/etat")}catch{a.value=null}}),(d,e)=>(i(),s(f,null,[e[4]||(e[4]=t("h1",null,"À propos",-1)),e[5]||(e[5]=t("p",{class:"sous-titre"},"Ce que ce site est, d'où viennent les données, et comment elles sont traitées.",-1)),t("div",q,[e[2]||(e[2]=l('<section class="item" data-v-8f7fd5b7><h2 data-v-8f7fd5b7>La mission</h2><div class="detail" data-v-8f7fd5b7><p data-v-8f7fd5b7> FasoCivic est une <strong data-v-8f7fd5b7>plateforme citoyenne indépendante</strong> qui rend l&#39;information publique du Burkina Faso accessible et interrogeable : décisions du Conseil des ministres, nominations officielles, textes de loi, engagements financiers de l&#39;État. </p><p data-v-8f7fd5b7> Ce projet n&#39;est affilié à aucun gouvernement, parti ou organisation politique. Il ne publie <strong data-v-8f7fd5b7>que des informations déjà publiques</strong>, issues des sites officiels, et chaque donnée affichée est reliée à son document source — vous pouvez toujours vérifier par vous-même. </p></div></section><section class="item" data-v-8f7fd5b7><h2 data-v-8f7fd5b7>Les sources</h2><div class="detail" data-v-8f7fd5b7><ul data-v-8f7fd5b7><li data-v-8f7fd5b7><a href="https://gouvernement.gov.bf" target="_blank" rel="noopener" data-v-8f7fd5b7>gouvernement.gov.bf</a> — comptes rendus officiels du Conseil des ministres (texte intégral ou PDF). </li><li data-v-8f7fd5b7><a href="https://www.legiburkina.gov.bf" target="_blank" rel="noopener" data-v-8f7fd5b7>Légiburkina (SGG-CM)</a> — décrets, lois, arrêtés et autres textes juridiques, avec leur Journal officiel de publication (<a href="https://www.jobf.gov.bf" target="_blank" rel="noopener" data-v-8f7fd5b7>jobf.gov.bf</a>). </li><li data-v-8f7fd5b7><a href="https://www.presidencedufaso.bf" target="_blank" rel="noopener" data-v-8f7fd5b7>presidencedufaso.bf</a> — communiqués de la Présidence du Faso. </li></ul><p data-v-8f7fd5b7> La collecte est automatique : toutes les 30 minutes pour les communiqués, chaque jeudi soir pour le Conseil des ministres, chaque matin pour les textes juridiques. Les documents originaux (HTML, PDF) sont archivés tels quels au moment de la collecte. </p></div></section>',2)),a.value?(i(),s("section",x,[e[1]||(e[1]=t("h2",null,"Fraîcheur des données",-1)),t("div",_,[a.value.muettes===0?(i(),s("p",C," Toutes les collectes sont à jour au regard de leur cadence. ")):(i(),s("p",k,[t("strong",null,o(a.value.muettes)+" source"+o(a.value.muettes>1?"s":""),1),e[0]||(e[0]=r(" en retard de collecte — nous en avons connaissance et travaillons à la remise à niveau. ",-1))])),t("ul",w,[(i(!0),s(f,null,m(a.value.sources,n=>(i(),s("li",{key:n.slug},[t("span",{class:h(["pastille",{ok:!n.muette}])},null,2),r(" "+o(n.nom)+" ",1),t("span",L,"— "+o(n.dernier_run_ok?u(n.dernier_run_ok):"jamais collectée"),1)]))),128))])])])):b("",!0),e[3]||(e[3]=l('<section class="item" data-v-8f7fd5b7><h2 data-v-8f7fd5b7>La méthode</h2><div class="detail" data-v-8f7fd5b7><ol data-v-8f7fd5b7><li data-v-8f7fd5b7><strong data-v-8f7fd5b7>Collecte</strong> — les documents sont récupérés depuis les sites officiels et archivés à l&#39;identique.</li><li data-v-8f7fd5b7><strong data-v-8f7fd5b7>Extraction</strong> — un modèle d&#39;intelligence artificielle structure la prose officielle (décisions, nominations, montants), avec un score de confiance pour chaque information extraite.</li><li data-v-8f7fd5b7><strong data-v-8f7fd5b7>Validation humaine</strong> — rien n&#39;est publié automatiquement : chaque décision, nomination ou engagement est revu avant d&#39;apparaître sur ce site.</li><li data-v-8f7fd5b7><strong data-v-8f7fd5b7>Traçabilité</strong> — chaque information affichée porte le lien vers le compte rendu ou le texte officiel dont elle provient.</li></ol></div></section><section class="item" data-v-8f7fd5b7><h2 data-v-8f7fd5b7>Les limites</h2><div class="detail" data-v-8f7fd5b7><p data-v-8f7fd5b7> L&#39;extraction automatique peut contenir des erreurs malgré la validation — un montant mal converti, une fonction mal rattachée. Les intitulés des ministères sont ceux en vigueur à la date de chaque document : un même ministère peut apparaître sous plusieurs noms au fil des remaniements. Les statistiques financières reflètent <em data-v-8f7fd5b7>ce qui est annoncé en Conseil des ministres</em>, pas l&#39;exécution réelle des dépenses. En cas de doute, la source officielle fait toujours foi. </p></div></section><section class="item" data-v-8f7fd5b7><h2 data-v-8f7fd5b7>Ouvert, réutilisable</h2><div class="detail" data-v-8f7fd5b7><p data-v-8f7fd5b7> Les données sont accessibles librement via une <a href="/api/docs" target="_blank" rel="noopener" data-v-8f7fd5b7>API publique documentée</a>, et le code de la plateforme est open source (licence GPL-3.0). Ce projet s&#39;inspire de <a href="https://www.vie-publique.sn" target="_blank" rel="noopener" data-v-8f7fd5b7>vie-publique.sn</a> (Code for Senegal). </p><p data-v-8f7fd5b7><strong data-v-8f7fd5b7>Télécharger les données (CSV) :</strong></p><ul class="telechargements" data-v-8f7fd5b7><li data-v-8f7fd5b7><a href="/api/export/nominations.csv" data-v-8f7fd5b7>Nominations</a> — toutes les nominations validées</li><li data-v-8f7fd5b7><a href="/api/export/annuaire.csv" data-v-8f7fd5b7>Annuaire de l&#39;État</a> — mandats consolidés</li><li data-v-8f7fd5b7><a href="/api/export/decisions.csv" data-v-8f7fd5b7>Décisions</a> — décisions du Conseil des ministres</li><li data-v-8f7fd5b7><a href="/api/export/engagements.csv" data-v-8f7fd5b7>Engagements financiers</a> — dépenses chiffrées en Conseil</li><li data-v-8f7fd5b7><a href="/api/export/textes.csv" data-v-8f7fd5b7>Lois &amp; décrets</a> — références des textes juridiques</li></ul><p class="note-licence" data-v-8f7fd5b7> Réutilisation libre en citant « FasoCivic » et la source officielle d&#39;origine. Chaque fichier inclut le lien vers le document source de chaque ligne. </p><p data-v-8f7fd5b7><strong data-v-8f7fd5b7>Suivre par flux RSS</strong> (dans votre lecteur, sans compte) :</p><ul class="telechargements" data-v-8f7fd5b7><li data-v-8f7fd5b7><a href="/api/rss/conseils.xml" data-v-8f7fd5b7>Conseils des ministres</a></li><li data-v-8f7fd5b7><a href="/api/rss/actualites.xml" data-v-8f7fd5b7>Actualités</a></li><li data-v-8f7fd5b7><a href="/api/rss/textes.xml" data-v-8f7fd5b7>Lois &amp; décrets</a></li></ul></div></section>',3))])],64))}},P=v(j,[["__scopeId","data-v-8f7fd5b7"]]);export{P as default};
